// Etapa 1+2: validar body, enmascarar credenciales, computar hash, determinar ceo_escalated preliminar.
// Output un solo item con _route in {invalid, valid}.
const raw = $input.first().json;
const body = (raw && typeof raw === 'object' && raw.body && typeof raw.body === 'object') ? raw.body : raw;

const VALID_ALERT_TYPES = new Set([
  'credential_exposed', 'infra_critical', 'cost_warning', 'cost_blocked',
  'workflow_failed', 'analytics_anomaly', 'system_health'
]);
const VALID_SEVERITIES = new Set(['P0', 'P1', 'P2', 'P3']);

const errors = [];
if (!body || typeof body !== 'object') errors.push('body must be a JSON object');
const alert_type = body && body.alert_type;
const severity = body && body.severity;
const source_skill = body && body.source_skill;
const trace_id = body && body.trace_id;
const payload = body && body.payload;
const timestamp = (body && body.timestamp) || new Date().toISOString();

if (!VALID_ALERT_TYPES.has(alert_type)) errors.push("alert_type invalid (one of " + [...VALID_ALERT_TYPES].join(',') + ")");
if (!VALID_SEVERITIES.has(severity)) errors.push("severity must be P0|P1|P2|P3");
if (typeof trace_id !== 'string' || trace_id.trim() === '') errors.push('trace_id required (non-empty string)');
if (!payload || typeof payload !== 'object') errors.push('payload required (object)');
if (payload && (typeof payload.title !== 'string' || payload.title.trim() === '')) errors.push('payload.title required');
if (payload && (typeof payload.description !== 'string' || payload.description.trim() === '')) errors.push('payload.description required');

if (errors.length > 0) {
  return [{ json: { _route: 'invalid', _status: 400, error: 'validation_failed', details: errors, trace_id: trace_id || null } }];
}

// Enmascaramiento — patrones canonicos skill #40 L.4.
// Orden: mas especificos primero, mas amplios despues.
const PATTERNS = [
  { name: 'aws_access_key',   re: /AKIA[0-9A-Z]{16}/g,                                                replacement: 'AKIA****REDACTED****' },
  { name: 'anthropic_api',    re: /sk-ant-api03-[A-Za-z0-9_-]+/g,                                    replacement: 'sk-ant-api03-****REDACTED****' },
  { name: 'openai_api',       re: /sk-(proj-)?[A-Za-z0-9_-]{40,}/g,                                  replacement: 'sk-****REDACTED****' },
  { name: 'github_classic',   re: /gh[ps]_[A-Za-z0-9]{36,}/g,                                        replacement: 'gh****REDACTED-GITHUB****' },
  { name: 'github_fine',      re: /github_pat_[A-Za-z0-9_]{82}/g,                                    replacement: 'github_pat_****REDACTED****' },
  { name: 'google_oauth',     re: /1\/\/[A-Za-z0-9_-]{40,}/g,                                        replacement: '1//****REDACTED-GOOGLE****' },
  { name: 'bearer_jwt',       re: /Bearer\s+eyJ[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+/g,    replacement: 'Bearer ****REDACTED-JWT****' },
  { name: 'credit_card',      re: /\b\d{4}[\s-]?\d{4}[\s-]?\d{4}[\s-]?(\d{4})\b/g,                  replacement: '****-****-****-$1' },
  { name: 'aws_secret_40',    re: /[A-Za-z0-9\/+=]{40}/g,                                            replacement: '****REDACTED-AWS-SECRET****' },
  { name: 'token_generic_50', re: /[A-Za-z0-9_-]{50,}/g,                                             replacement: '****REDACTED-TOKEN****', contextual: true }
];

let masked_count = 0;
const masked_breakdown = {};

function maskString(input, contextLabel) {
  if (typeof input !== 'string') return input;
  let out = input;
  for (const p of PATTERNS) {
    if (p.contextual) {
      const ctx = (contextLabel || '').toLowerCase();
      const inputLower = out.toLowerCase();
      const hasCtx = /\b(token|key|secret|password|api[_-]?key|auth)/i.test(ctx) || /\b(token|key|secret|password|api[_-]?key|auth)/i.test(inputLower);
      if (!hasCtx) continue;
    }
    let count = 0;
    out = out.replace(p.re, (match, ...rest) => {
      count++;
      if (typeof p.replacement === 'string' && p.replacement.includes('$1')) {
        return p.replacement.replace('$1', rest[0] || '');
      }
      return p.replacement;
    });
    if (count > 0) {
      masked_count += count;
      masked_breakdown[p.name] = (masked_breakdown[p.name] || 0) + count;
    }
  }
  return out;
}

function maskDeep(value, contextKey) {
  if (typeof value === 'string') return maskString(value, contextKey);
  if (Array.isArray(value)) return value.map((v, i) => maskDeep(v, contextKey + '[' + i + ']'));
  if (value && typeof value === 'object') {
    const out = {};
    for (const k of Object.keys(value)) out[k] = maskDeep(value[k], k);
    return out;
  }
  return value;
}

const payload_masked = {
  title: maskString(payload.title, 'title'),
  description: maskString(payload.description, 'description'),
  context: maskDeep(payload.context || {}, 'context')
};

// Hash trace = FNV-1a 64-bit (n8n Code node bloquea 'crypto' module — dedup no requiere cripto-fuerza).
// Misma propiedad: same input → same 16-hex output. Colision-resistente suficiente para dedup en ventana 30min.
const hashInput = String(alert_type) + '|' + String(source_skill || '') + '|' + String(payload.title) + '|' + String(payload.description);
function fnv1a64Hex(str) {
  // FNV-1a 64-bit using BigInt
  const FNV_OFFSET = 0xcbf29ce484222325n;
  const FNV_PRIME = 0x100000001b3n;
  const MASK = 0xffffffffffffffffn;
  let h = FNV_OFFSET;
  for (let i = 0; i < str.length; i++) {
    h = h ^ BigInt(str.charCodeAt(i));
    h = (h * FNV_PRIME) & MASK;
  }
  return h.toString(16).padStart(16, '0');
}
const hash_trace = fnv1a64Hex(hashInput);

// Determinar ceo_escalated preliminar (Y.1 routing map).
const ctx = (payload && payload.context) || {};
let ceo_escalated = false;
switch (alert_type) {
  case 'credential_exposed':
    ceo_escalated = !!ctx.requires_ceo_escalation; break;
  case 'infra_critical':
    ceo_escalated = true; break; // re-evaluado tras self-heal placeholder (siempre falla hoy)
  case 'cost_warning':
  case 'cost_blocked':
    ceo_escalated = !!ctx.requires_ceo_escalation; break;
  case 'workflow_failed':
    ceo_escalated = (Number(ctx.client_affected_days) || 0) >= 1; break;
  case 'analytics_anomaly':
    ceo_escalated = !!ctx.severe_impact; break;
  case 'system_health':
    ceo_escalated = !!ctx.unresolvable_by_pm; break;
}

// Log estructurado pm2 si masked_count > 0.
if (masked_count > 0) {
  console.log("COST_GUARD_ALERT level:WARN type:CREDENTIAL_DETECTED_IN_ALERT trace_id:" + trace_id + " masked_count:" + masked_count + " breakdown:" + JSON.stringify(masked_breakdown));
}

// Inbox payload Redis (lo que el #4 PM consumira).
const now_iso = new Date().toISOString();
const inbox_payload = {
  trace_id: trace_id,
  alert_type: alert_type,
  severity: severity,
  source_skill: source_skill || null,
  timestamp: timestamp,
  received_at: now_iso,
  ceo_escalated: ceo_escalated, // re-actualizado despues si infra_critical
  deduplicated: false,
  masked_count: masked_count,
  masked_breakdown: masked_breakdown,
  payload: payload_masked,
  inbox_path_redis: 'agent:4:inbox:' + trace_id
};

return [{
  json: {
    _route: 'valid',
    trace_id: trace_id,
    alert_type: alert_type,
    severity: severity,
    source_skill: source_skill || null,
    timestamp: timestamp,
    hash_trace: hash_trace,
    cooldown_key: 'alert:cooldown:' + hash_trace,
    inbox_key: 'agent:4:inbox:' + trace_id,
    ceo_escalated: ceo_escalated,
    masked_count: masked_count,
    masked_breakdown: masked_breakdown,
    payload_masked: payload_masked,
    inbox_payload: inbox_payload,
    inbox_payload_json: JSON.stringify(inbox_payload)
  }
}];

// Etapa 3 fail-closed: Redis GET fallo. Por invariante: NO escalar al CEO con flujo descontrolado.
// Tratamos como deduplicado defensivo: log + respuesta 200 con fail_closed:true.
const meta = $('Validate Mask Hash').first().json;
const err = $input.first().json;
const errMsg = (err && (err.error || err.message)) ? (err.error || err.message) : JSON.stringify(err);
console.log("ALERT_ROUTER_REDIS_FAIL_CLOSED trace_id:" + meta.trace_id + " error:" + String(errMsg));

return [{
  json: Object.assign({}, meta, {
    _route: 'fail_closed',
    _status: 200,
    response_body: {
      deduplicated: true,
      fail_closed: true,
      reason: 'redis_unreachable_failed_closed_per_invariant_2',
      trace_id: meta.trace_id,
      alert_type: meta.alert_type,
      ceo_escalated: false,
      credential_masked_count: meta.masked_count,
      pm_inbox_key: null,
      telegram_sent: false,
      email_sent: false
    }
  })
}];

// Etapa 3: Inspeccionar output del Redis GET cooldown.
// Si hay valor previo → _route = deduplicated. Si vacio → _route = fresh.
const meta = $('Validate Mask Hash').first().json;
const input = $input.first().json;

// El nodo Redis GET retorna un objeto cuya propiedad coincide con la key (o un alias).
let rawValue = null;
if (input && typeof input === 'object') {
  for (const k of Object.keys(input)) {
    if (input[k] !== undefined && input[k] !== null && input[k] !== '') {
      rawValue = input[k];
      break;
    }
  }
}

if (rawValue !== null && rawValue !== undefined && rawValue !== '') {
  console.log("ALERT_DEDUPED type:" + meta.alert_type + " trace_id:" + meta.trace_id + " original_trace_id:" + String(rawValue));
  return [{
    json: Object.assign({}, meta, {
      _route: 'deduplicated',
      _status: 200,
      original_trace_id: String(rawValue),
      current_trace_id: meta.trace_id,
      response_body: {
        deduplicated: true,
        original_trace_id: String(rawValue),
        current_trace_id: meta.trace_id,
        alert_type: meta.alert_type,
        trace_id: meta.trace_id,
        ceo_escalated: false,
        credential_masked_count: meta.masked_count,
        pm_inbox_key: null,
        telegram_sent: false,
        email_sent: false
      }
    })
  }];
}

return [{ json: Object.assign({}, meta, { _route: 'fresh' }) }];

// Etapa 4 case infra_critical: invocar Self-Heal Validator (placeholder Y.6.1).
// TODO Y.6.1: construir workflow Self-Heal Validator con HTTP 200 check + smoke test workflow blog-don-jacinto.
// Hoy: simular siempre {recovered: false} → escalar al CEO.
const meta = $input.first().json;
if (meta.alert_type !== 'infra_critical') {
  // Pass-through para alert_types que no requieren self-heal.
  return [{ json: meta }];
}

const self_heal_result = { recovered: false, placeholder: true, note: 'Self-Heal Validator workflow Y.6.1 pendiente — siempre escala hasta construirlo' };
console.log("INFRA_SELF_HEAL_PLACEHOLDER trace_id:" + meta.trace_id + " result:false");

// Forzar ceo_escalated=true para infra_critical hasta que Y.6.1 exista.
const updated = Object.assign({}, meta, {
  ceo_escalated: true,
  self_heal_attempted: true,
  self_heal_recovered: false,
  inbox_payload: Object.assign({}, meta.inbox_payload, { ceo_escalated: true, self_heal_attempted: true, self_heal_recovered: false })
});
updated.inbox_payload_json = JSON.stringify(updated.inbox_payload);
return [{ json: updated }];

